class YazQueue:
    def __init__(self):
        self._queue = []

    def is_empty(self) -> bool:
        return len(self._queue) == 0

    def size(self) -> int:
        return len(self._queue)

    def _get_middle_index_for_access(self) -> int:
        return (len(self._queue) - 1) // 2

    def _get_middle_index_for_insertion(self) -> int:
        return len(self._queue) // 2

    def push_front(self, value):
        self._queue.insert(0, value)

    def pop_front(self):
        if self.is_empty():
            raise IndexError("pop_front from empty YazQueue")
        return self._queue.pop(0)

    def peek_front(self):
        if self.is_empty():
            raise IndexError("peek_front from empty YazQueue")
        return self._queue[0]

    def push_back(self, value):
        self._queue.append(value)

    def pop_back(self):
        if self.is_empty():
            raise IndexError("pop_back from empty YazQueue")
        return self._queue.pop()

    def peek_back(self):
        if self.is_empty():
            raise IndexError("peek_back from empty YazQueue")
        return self._queue[-1]

    def push_middle(self, value):
        middle_idx = self._get_middle_index_for_insertion()
        self._queue.insert(middle_idx, value)

    def pop_middle(self):
        if self.is_empty():
            raise IndexError("pop_middle from empty YazQueue")
        middle_idx = self._get_middle_index_for_access()
        return self._queue.pop(middle_idx)

    def peek_middle(self):
        if self.is_empty():
            raise IndexError("peek_middle from empty YazQueue")
        middle_idx = self._get_middle_index_for_access()
        return self._queue[middle_idx]

    def __repr__(self):
        return f"YazQueue({self._queue})"

    def __str__(self):
        return f"[{', '.join(map(str, self._queue))}]"
